Tool.Code:
def validate_spacing_consistency(spacing_values: list, scale: list = [0, 4, 8, 12, 16, 24, 32, 48, 64]) -> dict:
    """Check if all spacing values are on the defined scale"""
    issues = []

    for value in spacing_values:
        if value not in scale:
            closest = min(scale, key=lambda x: abs(x - value))
            issues.append(f"{value}px not on scale; use {closest}px")

    return {
        "passed": len(issues) == 0,
        "on_scale_count": len(spacing_values) - len(issues),
        "total_count": len(spacing_values),
        "issues": issues
    }

def validate_component_states(component: dict) -> dict:
    """Check if component has all required states"""
    required_states = ["default", "hover", "focus", "active", "disabled"]
    optional_states = ["loading", "error", "success"]

    issues = []
    defined_states = component.get("states", [])

    for state in required_states:
        if state not in defined_states:
            issues.append(f"Missing required state: {state}")

    return {
        "passed": len(issues) == 0,
        "required_coverage": f"{len(defined_states) - len(issues)}/{len(required_states)}",
        "has_optional": [s for s in optional_states if s in defined_states],
        "issues": issues
    }
